import { Link } from "react-router-dom";

function LeagueMenu() {
    return (
        <div className="league-menu">
            <h1>League Menu</h1>
            <div className="jornadas-lista">
                <h1>Jornadas</h1>
                
            </div>
            <div className="menu-options">
                <Link to="/team-list" className="menu-link">
                    <button className="menu-button">View Team List</button>
                </Link>
            </div>
        </div>
    );
}

export default LeagueMenu;
